"""
MKT Original Commentary — John chapters 14–16
Run: python3 scripts/zc-original-john-14-16.py

Source data used:
- data/interlinear/john.json
- data/translation/glossary-greek.json (contested terms)
- data/translation/notes/john.json (translation reasoning)
- data/translation/draft/mediating/john.json (MKT text for quoting)

Key decisions in this range:
- παράκλητος (G3875): rendered "Advocate" in MKT; commentary notes full semantic range
  (legal defender, helper, intercessor) and why "Comforter" (KJV) is too narrow
- μένω (G3306): "remain" preferred over "abide" — commentary notes the persistent-state
  aspect of the present imperative
- ἀληθινός (G228) vs ἀληθής (G227): "true" in 15:1 is alēthinós — genuine/real, not merely
  accurate; commentary marks the distinction
- αἴρω / καθαίρω (15:2) wordplay: same root, opposite actions; lost in English
- ἐλέγχω (G1651) in 16:8: semantic range spans "convict," "expose," "reprove," "convince" —
  commentary notes the forensic register
- δικαιοσύνη (G1343) dispute_level 4: commentary acknowledges range of translations
- "the Father is greater than I" (14:28): ὁ πατὴρ μείζων μού ἐστιν treated as relational
  statement within the mission, not ontological subordination
- "all the truth" (16:13): εἰς τὴν ἀλήθειαν πᾶσαν — anarthrous in some mss; commentary
  notes the article variant does not change the sense materially
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOHN = {
  "14": {
    "1": '<p><strong>μὴ ταρασσέσθω ὑμῶν ἡ καρδία</strong> — "Let not your heart be troubled." The verb <em>tarasséō</em> (G5015) is present passive imperative — "stop being troubled," or "do not continue in the state of being shaken." The same verb appears in 5:7 of the stirred pool, and in 13:21 where Jesus himself is described as "troubled in spirit." The command is not to suppress emotion but to redirect trust: the next clause sets up the ground — "believe in God; also believe in me." The conjunction <em>kai</em> ("also") links belief in God and belief in Jesus as parallel acts, not sequential ones.</p>',
    "2": '<p><strong>ἐν τῇ οἰκίᾳ τοῦ πατρός μου μοναὶ πολλαί εἰσιν</strong> — "In my Father\'s house there are many dwelling-places." <em>Monē</em> (G3438) — from <em>menō</em> (to remain) — is a place of stable, enduring residence, not a temporary lodging. The cognate connection matters: the "dwelling-place" Jesus promises is the same root as the "remaining" (μένω) that structures the vine discourse in chapter 15.</p><p><strong>εἰ δὲ μή</strong> — the conditional clause is difficult. The Greek reads: "if it were not so, I would have told you." The Evangelist presents Jesus as affirming the Father\'s house as a known reality, not a speculative hope. The purpose clause <em>ἑτοιμάσαι τόπον ὑμῖν</em> ("to prepare a place for you") uses aorist infinitive — a decisive, completed preparation, not an ongoing process.</p>',
    "3": '<p><strong>καὶ ἐὰν πορευθῶ καὶ ἑτοιμάσω τόπον ὑμῖν, πάλιν ἔρχομαι</strong> — the two aorist subjunctives (<em>poreutho</em>, <em>hetoimasō</em>) express the contingent departure-and-preparation; then the present indicative <em>érchomai</em> ("I am coming") shifts the return to a certain, already-in-motion reality. The present is used as a definite future: the return is so certain it is stated as a present fact. <strong>παραλήμψομαι ὑμᾶς πρὸς ἐμαυτόν</strong> — "I will take you to myself" — the verb <em>paralambánō</em> carries the sense of active reception, like taking someone by the hand to bring alongside.</p>',
    "4": '<p><strong>καὶ ὅπου ἐγὼ ὑπάγω οἴδατε τὴν ὁδόν</strong> — "And where I am going, you know the way." The emphatic <em>egō</em> ("I") separates the subject from the verb. <em>Oídate</em> (G1492, perfect of <em>eidon</em>) carries the force of "you have come to know and it stands known." Thomas\'s immediate objection in v5 exposes that their knowledge is more implicit than they realize — the declaration is anticipatory, not descriptive of their current self-understanding.</p>',
    "5": '<p><strong>οὐκ οἴδαμεν ποῦ ὑπάγεις</strong> — Thomas\'s reply uses the same verb <em>oidamen</em> (perfect "we have known"), but negated: "we have not come to know." The exchange turns on the same word — Jesus asserts they know the way; Thomas counters they do not even know the destination. The mismatch sets up the I-AM saying of v6: the way is not a route to a known place but a person.</p>',
    "6": '<p><strong>ἐγώ εἰμι ἡ ὁδὸς καὶ ἡ ἀλήθεια καὶ ἡ ζωή</strong> — the sixth predicated I-AM saying of the Fourth Gospel. Three nouns with articles, all in the nominative, linked by <em>kai … kai</em>: "the way, and the truth, and the life." The article before each noun ("the" way, "the" truth, "the" life) is definitive — not one path among many, not a truth among truths. <em>Hodós</em> (G3598) is way, road, path — the means of movement; <em>alētheia</em> (G225) is truth as unconcealedness, reality as it actually is; <em>zōē</em> (G2222) is life in the Johannine sense — the life of the age to come, already present in the Son (1:4).</p><p><strong>οὐδεὶς ἔρχεται πρὸς τὸν πατέρα εἰ μὴ δι᾽ ἐμοῦ</strong> — "no one comes to the Father except through me." The double-negative pattern of the LXX exclusives: <em>oudeis</em> … <em>ei mē</em> — absolute. The preposition <em>dia</em> with the genitive ("through me") marks agency and mediation, not merely association.</p>',
    "7": '<p><strong>εἰ ἐγνώκειτέ με, καὶ τὸν πατέρα μου ἂν ᾔδειτε</strong> — a mixed past counterfactual. <em>Egnōkeite</em> is pluperfect of <em>ginōskō</em> (relational, experiential knowing); <em>ēdeite</em> is pluperfect of <em>oida</em> (complete, settled knowledge). The sentence distinguishes two kinds of knowing: if you had truly known me (relational knowing), you would already possess settled knowledge of the Father. From v7b, the counterfactual flips to an affirmation: "from now on, you do know him and have seen him" — present tense, applying the completed work of revelation.</p>',
    "8": '<p><strong>κύριε, δεῖξον ἡμῖν τὸν πατέρα</strong> — Philip\'s request uses the aorist imperative <em>deixon</em> — "show us" as a single act. The word <em>deíknymi</em> (G1166) means to make visible, to display. Philip imagines a theophany separable from Jesus — a visible display of the Father as a distinct event. The irony is that the display has been ongoing throughout the ministry. <strong>καὶ ἀρκεῖ ἡμῖν</strong> — "and it will be enough for us." <em>Arkeō</em> (G714) — to suffice, to be content — implies that what they have seen in Jesus is insufficient; the reply in v9 overturns this assumption.</p>',
    "9": '<p><strong>τοσούτῳ χρόνῳ μεθ᾽ ὑμῶν εἰμι</strong> — "such a long time I am with you." The dative <em>tosoutō chronō</em> marks duration — Jesus has been present as a fact of ongoing experience. The perfect-present combination charges Philip\'s failure to recognize: "so long a time" of seeing (θεωρέω) without perceiving.</p><p><strong>ὁ ἑωρακὼς ἐμὲ ἑώρακεν τὸν πατέρα</strong> — "the one having seen me has seen the Father." Both verbs are perfect tense: <em>heōrakōs</em> (having seen, with the result standing) and <em>heōraken</em> (has seen and it stands seen). The perfect asserts that seeing Jesus is not preparation for seeing the Father later — it is the seeing of the Father, already accomplished.</p>',
    "10": '<p><strong>τὰ ῥήματα ἃ ἐγὼ λέγω ὑμῖν ἀπ᾽ ἐμαυτοῦ οὐ λαλῶ</strong> — the distinction between two speaking verbs: <em>légō</em> (G3004, to say — the content) and <em>laléō</em> (G2980, to speak — the act of speaking). Jesus says: the things I say I do not speak from myself. The content of his words and the utterance of his speech both originate in the Father. <strong>ὁ δὲ πατὴρ ὁ ἐν ἐμοὶ μένων ποιεῖ τὰ ἔργα αὐτοῦ</strong> — "the Father who remains in me does his works." <em>Menōn</em> is present participle of <em>menō</em> — the Father\'s indwelling is ongoing, not sporadic. The works (<em>erga</em>) are the Father\'s own, performed through the Son.</p>',
    "11": '<p><strong>πιστεύετέ μοι … εἰ δὲ μή, διὰ τὰ ἔργα αὐτὰ πιστεύετε</strong> — a two-tier appeal to belief, both using present imperative <em>pisteuete</em>. The first tier asks belief grounded in the mutual indwelling claim (v10); the second — "if not, believe for the sake of the works themselves" — appeals to the observable evidence of the works as a lower but valid ground. The pattern recurs from 10:38: the works testify when the words are not received.</p>',
    "12": '<p><strong>ὁ πιστεύων εἰς ἐμὲ τὰ ἔργα ἃ ἐγὼ ποιῶ κἀκεῖνος ποιήσει</strong> — "the one believing in me will do the works I do." Present participle <em>pisteuōn</em> — the one who is (continuously) believing. The future <em>poiēsei</em> is a straight promise. <strong>μείζονα τούτων ποιήσει</strong> — "greater than these will he do." <em>Meizōn</em> (G3187, comparative of <em>megas</em>) — greater in scope and extent, not in kind. The ground for this claim: "because I am going to the Father" — the departure enables the Spirit\'s coming (16:7), and the Spirit\'s coming enables the mission\'s worldwide reach.</p>',
    "13": '<p><strong>καὶ ὅ τι ἂν αἰτήσητε ἐν τῷ ὀνόματί μου τοῦτο ποιήσω</strong> — "whatever you ask in my name, this I will do." The phrase <em>en tō onomati mou</em> ("in my name") does not mean invoking Jesus as a formula; in Semitic thought, "name" encompasses identity, authority, and character. To ask "in the name of" Jesus is to ask as his representative, in alignment with his character and mission. <strong>ἵνα δοξασθῇ ὁ πατὴρ ἐν τῷ υἱῷ</strong> — the purpose clause: "so that the Father may be glorified in the Son." The aorist passive subjunctive <em>doxasthē</em> ties answered prayer to the Father\'s glorification — not a blank check but a shaped promise.</p>',
    "14": '<p><strong>ἐάν τι αἰτήσητέ με ἐν τῷ ὀνόματί μου ἐγὼ ποιήσω</strong> — v14 repeats v13 with one addition: the pronoun <em>me</em> ("you ask me") in some manuscripts, making Jesus himself the object of the petition, not merely the name invoked in a petition to the Father. This variant is well-attested (P66, Sinaiticus, Vaticanus) and shifts the addressee of prayer: in these texts, Jesus explicitly receives petitions made "in his name." The emphasis on repetition in vv13–14 underscores the certainty of the promise.</p>',
    "15": '<p><strong>ἐὰν ἀγαπᾶτέ με, τὰς ἐντολάς τὰς ἐμὰς τηρήσετε</strong> — the conditional is present subjunctive: "if you love me [as an ongoing disposition], you will keep my commandments." The future indicative <em>tērēsete</em> is not an imperative but a prediction: love issues in obedience naturally. <em>Tēréō</em> (G5083) — to guard, to keep watch over — is stronger than mere compliance; it implies vigilant preservation of what has been entrusted. The possessive <em>tas emas</em> ("my commandments") emphasizes that these are not the Mosaic commands but the commands of Jesus as covenant mediator.</p>',
    "16": '<p><strong>κἀγὼ ἐρωτήσω τὸν πατέρα καὶ ἄλλον παράκλητον δώσει ὑμῖν</strong> — the first appearance of <strong>παράκλητος</strong> (<em>Paráklētos</em>, G3875) in the Gospel. The word is a legal and relational term: one called alongside (<em>para</em> + <em>kaleō</em>) to help, support, advocate, or defend. In Hellenistic legal usage, a <em>paraklētos</em> is a defense advocate in court. Philo uses it of an intercessor with God. The KJV "Comforter" (from Latin <em>comfortare</em>) captures one dimension but misses the legal freight. "Advocate" recovers the forensic register; "Helper" is also defensible.</p><p><strong>ἄλλον</strong> — "another" of the same kind (G243, <em>allos</em>, not G2087, <em>heteros</em> — another of a different kind). The implication is that Jesus himself has been functioning as <em>Paráklētos</em> for the disciples — 1 John 2:1 makes this explicit. The Spirit is a second Advocate of the same order. <strong>εἰς τὸν αἰῶνα</strong> — "forever" — <em>eis ton aiōna</em>, into the age, with perpetuity: the Spirit\'s presence is permanent in a way that Jesus\'s physical presence was not.</p>',
    "17": '<p><strong>τὸ πνεῦμα τῆς ἀληθείας</strong> — "the Spirit of truth." The genitive is appositional: the Spirit who is truth, or the Spirit characterized by truth. <em>Alētheia</em> (G225) in John always carries ontological weight — truth as unconcealedness, the way things actually are before God. The Spirit does not merely teach accurate facts; he mediates genuine reality as opposed to the world\'s distorted perception.</p><p><strong>ὃ ὁ κόσμος οὐ δύναται λαβεῖν</strong> — "whom the world cannot receive." <em>Dúnamai</em> (G1410, present indicative) — not merely "does not" but "cannot" — the incapacity is structural, not circumstantial. <strong>ὅτι οὐ θεωρεῖ αὐτὸ οὐδὲ γινώσκει</strong> — "because it neither sees him nor knows him." Two verbs: <em>theōréō</em> (G2334, perceptual seeing) and <em>ginōskō</em> (relational knowing) — the world lacks both. <strong>ὑμεῖς δὲ γινώσκετε αὐτό</strong> — "but you know him" — emphatic <em>hymeis</em> ("you" in contrast to "the world"). The present tense suggests the disciples already have this knowing, even if not yet conscious of its full extent.</p>',
    "18": '<p><strong>οὐκ ἀφήσω ὑμᾶς ὀρφανούς</strong> — "I will not leave you orphans." <em>Orphanós</em> (G3737) — literally, a child bereft of a father; metaphorically, one without a patron or protector in the Greco-Roman world. Orphans were among the most legally and socially vulnerable in antiquity. The word activates both the familial and the social-protection register. <strong>ἔρχομαι πρὸς ὑμᾶς</strong> — "I am coming to you" — again the present as certain future (cf. 14:3). The question of whether this refers to the resurrection appearances, the Spirit\'s coming, or the parousia is debated; the Evangelist may intend the ambiguity to encompass all three.</p>',
    "19": '<p><strong>ἔτι μικρὸν καὶ ὁ κόσμος με οὐκέτι θεωρεῖ</strong> — "yet a little while and the world sees me no longer." <em>Mikrón</em> (G3397, a little while) — the same phrase frames 16:16–19. <em>Theōréō</em> (G2334) — extended perceptual seeing. The world\'s sight of Jesus ends with the crucifixion. <strong>ὑμεῖς δὲ θεωρεῖτε με</strong> — "but you see me" — same verb, present tense: the disciples\' seeing continues past the world\'s horizon. The basis: "because I live, you also will live." <em>Zō</em> (G2198, present indicative) — "I live" — the resurrection life of Jesus is stated as an ongoing present fact that grounds the disciples\' future life.</p>',
    "20": '<p><strong>ἐν ἐκείνῃ τῇ ἡμέρᾳ γνώσεσθε</strong> — "on that day you will know." The future <em>gnōsesthe</em> (G1097) — the knowing is coming but is not yet complete. "That day" is the day of recognition that comes with the Spirit\'s arrival and the resurrection. Three mutual indwellings are stated: "I am in my Father, and you in me, and I in you" — a nested mutual indwelling that mirrors the mutual knowing of 10:14–15 (Father-Son-sheep). The grammar is paratactic: three <em>ens</em> (in) without subordination, all equally real.</p>',
    "21": '<p><strong>ὁ ἔχων τὰς ἐντολάς μου καὶ τηρῶν αὐτάς</strong> — two participles: "the one having my commands" (<em>echōn</em>) and "keeping them" (<em>tērōn</em>). Possession without keeping is insufficient; keeping without possession is impossible. <strong>κἀγὼ ἀγαπήσω αὐτὸν καὶ ἐμφανίσω αὐτῷ ἐμαυτόν</strong> — "I will love him and reveal myself to him." <em>Emphanízō</em> (G1718) — to make visible, to disclose, to cause to appear. The verb appears in the Exodus context for God showing his glory (Exod 33:13 LXX). The self-disclosure of Jesus is conditioned on the love-obedience relationship.</p>',
    "22": '<p><strong>τί γέγονεν ὅτι ἡμῖν μέλλεις ἐμφανίζειν σεαυτὸν καὶ οὐχὶ τῷ κόσμῳ</strong> — Judas (not Iscariot) raises a reasonable question: if Jesus is going to reveal himself, why not universally? The verb <em>emphanízō</em> from v21 is repeated — the disciples have registered the word. The question implies they expected a public, triumphant Messiah. Jesus\'s answer redefines revelation: it is relational (love + obedience), not spectacular.</p>',
    "23": '<p><strong>ἐάν τις ἀγαπᾷ με, τὸν λόγον μου τηρήσει</strong> — "if anyone loves me, he will keep my word." Note the shift from <em>entolás</em> (commandments, plural, vv15, 21) to <em>ton logon mou</em> ("my word," singular): the totality of Jesus\'s teaching as an integrated whole, not individual commands. <strong>καὶ πρὸς αὐτὸν ἐλευσόμεθα καὶ μονὴν παρ᾽ αὐτῷ ποιησόμεθα</strong> — "and we will come to him and make our dwelling with him." The plural "we" — Father and Son — is striking; the inhabitation is Trinitarian. <em>Monēn</em> (G3438, dwelling-place) returns from v2: the "many dwelling-places" in the Father\'s house and the dwelling made in the obedient believer are cognate realities.</p>',
    "24": '<p><strong>ὁ μὴ ἀγαπῶν με τοὺς λόγους μου οὐ τηρεῖ</strong> — the negative form of v23: "the one not loving me does not keep my words." Present tense throughout — ongoing states. <strong>καὶ ὁ λόγος ὃν ἀκούετε οὐκ ἔστιν ἐμὸς ἀλλὰ τοῦ πέμψαντός με πατρός</strong> — "the word you hear is not mine but the Father\'s who sent me." The aorist participle <em>tou pempsantos me</em> — "of the one who sent me" — is one of the Evangelist\'s characteristic phrases for the Father\'s commissioning authority (cf. 5:37; 7:28; 8:26). The refusal to receive Jesus\'s word is thereby a refusal of the Father\'s word.</p>',
    "25": '<p><strong>ταῦτα λελάληκα ὑμῖν παρ᾽ ὑμῖν μένων</strong> — "these things I have spoken to you while remaining with you." The perfect <em>lelalēka</em> — "I have spoken and the speaking stands" — a summary of the entire Farewell Discourse before it is technically over. <em>Par᾽ hymīn menōn</em> — "while remaining alongside you" — <em>menō</em> again: the physical remaining of Jesus with the disciples is about to end; the Spirit\'s remaining (v17: <em>men</em>ει παρ᾽ ὑμῖν) will replace it.</p>',
    "26": '<p><strong>ὁ δὲ παράκλητος, τὸ πνεῦμα τὸ ἅγιον</strong> — the second Paraclete saying. Here the Paraclete is explicitly identified as "the Holy Spirit," and the sending agent shifts: "whom the Father will send in my name." In 15:26, Jesus sends the Spirit from the Father; here the Father sends the Spirit in the name of Jesus — both are true, the persons of the Trinity acting in coordinated mission.</p><p><strong>ἐκεῖνος ὑμᾶς διδάξει πάντα</strong> — "that one will teach you all things." <em>Ekéinos</em> is an emphatic demonstrative — "that one" — used to distinguish the Spirit from Jesus as a second distinct person with agency. <em>Didáxei</em> (G1321, future of <em>didáskō</em>) — will teach: the Spirit continues and completes what Jesus began. <strong>καὶ ὑπομνήσει ὑμᾶς πάντα ἃ εἶπον ὑμῖν ἐγώ</strong> — "and will remind you of all that I said to you." <em>Hypomnēsei</em> (G5279, to remind, to call to memory) — the Spirit\'s work grounds the apostolic recollection of Jesus\'s teaching; John\'s Gospel itself is implicitly presented as the product of this anamnesis.</p>',
    "27": '<p><strong>εἰρήνην ἀφίημι ὑμῖν, εἰρήνην τὴν ἐμὴν δίδωμι ὑμῖν</strong> — "Peace I leave with you; my peace I give to you." Two verbs: <em>aphíēmi</em> (to release, to send away — the farewell bestowal) and <em>dídōmi</em> (to give — the active gift). <em>Eirēnē</em> (G1515) translates <em>shalom</em> — wholeness, well-being, right relationship, not merely absence of conflict. The possessive <em>tēn emēn</em> — "my peace" — distinguishes this from a generic benediction: it is the specific peace that characterizes Jesus himself, grounded in his relationship with the Father.</p><p><strong>οὐ καθὼς ὁ κόσμος δίδωσιν ἐγὼ δίδωμι ὑμῖν</strong> — "not as the world gives, I give to you." The world\'s giving is conditional, transactional, temporary. Jesus\'s giving is permanent (v16: "forever") and unconditional. <strong>μὴ ταρασσέσθω ὑμῶν ἡ καρδία μηδὲ δειλιάτω</strong> — the chapter that opened with "do not let your heart be troubled" closes with the same prohibition plus <em>deiliaō</em> (G1167, to be cowardly, to shrink in fear). Two present imperatives: stop being troubled, stop being afraid.</p>',
    "28": '<p><strong>ὁ πατὴρ μείζων μού ἐστιν</strong> — "the Father is greater than I." This verse is among the most contested in Johannine Christology. <em>Meízōn</em> (G3187, comparative of <em>megas</em>) — greater. The statement follows "I am going to the Father" — the context is missional and relational: the Son going back to the one who sent him, returning to the Father who is the source of the mission. The text does not say "greater in being" but "greater" without specification; interpreters who read this ontologically (Arius) press the text further than its context requires. Within John\'s own framework (1:1; 10:30; 20:28), the subordination operative here is functional and economic, not ontological. The note of rebuke — "if you loved me, you would have rejoiced" — grounds Jesus\'s departure not in loss but in the Father\'s greatness as the goal of the Son\'s return.</p>',
    "29": '<p><strong>καὶ νῦν εἴρηκα ὑμῖν πρὶν γενέσθαι</strong> — "and now I have told you before it happens." The perfect <em>eirēka</em> — "I have spoken and it stands spoken" — is the Evangelist\'s recurring formula for completed disclosure. The aorist infinitive <em>genésthai</em> — "before happening" — marks the events as temporally future from the moment of speech. <strong>ἵνα ὅταν γένηται πιστεύσητε</strong> — "so that when it happens, you may believe." The purpose clause shapes the prophetic function of Jesus\'s words: not merely to inform but to produce belief when the events confirm the prediction.</p>',
    "30": '<p><strong>ὁ τοῦ κόσμου ἄρχων</strong> — "the ruler of this world." <em>Árchōn</em> (G758) — ruler, chief, magistrate — is used three times in the Gospel for the devil (12:31; 14:30; 16:11). The title acknowledges real dominion over the present age, while the next clause strips away its power: <strong>ἐν ἐμοὶ οὐκ ἔχει οὐδέν</strong> — "in me he has nothing." The phrase <em>ouden echei</em> means "has no claim," "has no foothold," "finds nothing to seize." The coming of the ruler is a confrontation, but Jesus meets it without any crack or leverage that evil can exploit.</p>',
    "31": '<p><strong>ἀλλ᾽ ἵνα γνῷ ὁ κόσμος ὅτι ἀγαπῶ τὸν πατέρα</strong> — "but that the world may know that I love the Father." The purpose of the passion is revelatory: the cross is the demonstration that Jesus loves the Father, enacted in total obedience. <strong>καθὼς ἐνετείλατό μοι ὁ πατήρ, οὕτως ποιῶ</strong> — "as the Father commanded me, so I do." <em>Eneteilato</em> (G1781, aorist — a definitive commissioning); <em>poiō</em> (G4160, present — ongoing execution of it). The aorist command of the Father and the present obedience of the Son in simultaneous relation. <strong>ἐγείρεσθε, ἄγωμεν ἐντεῦθεν</strong> — "Rise, let us go from here." Present imperative + hortatory subjunctive. The discourse ends in motion: the theology of the cross is immediately enacted.</p>'
  },
  "15": {
    "1": '<p><strong>ἐγώ εἰμι ἡ ἄμπελος ἡ ἀληθινή</strong> — the seventh and final predicated I-AM saying of the Gospel. <em>Ampelos</em> (G288) — vine. <em>Alēthinós</em> (G228) — genuine, real, as opposed to merely <em>alēthēs</em> (accurate, truthful). The distinction matters: Israel was the vine (Ps 80:8; Isa 5:1–7; Jer 2:21), but a vine that produced sour grapes, withered and failed. Jesus is the <em>alēthinē</em> vine — the genuine article, the fulfillment of what Israel\'s vine was always meant to be, not merely a true-rather-than-false vine. <strong>ὁ πατήρ μου ὁ γεωργός ἐστιν</strong> — "my Father is the gardener." <em>Geōrgós</em> (G1092) — farmer, vine-dresser, one who works the earth. The Father is the active cultivator, tending the vine and its branches with purposeful skill.</p>',
    "2": '<p><strong>πᾶν κλῆμα ἐν ἐμοὶ μὴ φέρον καρπόν, αἴρει αὐτό</strong> — "every branch in me not bearing fruit, he takes away." <em>Aírō</em> (G142) — to lift up and take away. The same verb is used for taking away sin (1:29) and lifting the blind man\'s mat (5:8). Here it is removal from the vine.</p><p><strong>καὶ πᾶν τὸ καρπὸν φέρον, καθαίρει αὐτό</strong> — "and every branch bearing fruit, he prunes it." <em>Kathaírō</em> (G2508) — to cleanse, to prune. The wordplay in Greek is audible: <em>aírō</em> (take away) and <em>kathaírō</em> (prune/cleanse) share the root <em>airō</em>. English loses this entirely. The action of the Father is not neutral: he removes the fruitless and purifies the fruitful. Both are active interventions in the vine.</p>',
    "3": '<p><strong>ἤδη ὑμεῖς καθαροί ἐστε διὰ τὸν λόγον ὃν λελάληκα ὑμῖν</strong> — "already you are clean because of the word I have spoken to you." The verb <em>kathairomai</em> from v2 (prune/cleanse) generates its adjective <em>katharoi</em> here — clean. The disciples have already been pruned by the word. The perfect <em>lelalēka</em> — "I have spoken and it stands spoken" — grounds their cleanness in a completed speech-act of Jesus. This echoes 13:10 ("you are clean, but not every one of you") — a cleanness that is real but not universal among the Twelve.</p>',
    "4": '<p><strong>μείνατε ἐν ἐμοί, κἀγὼ ἐν ὑμῖν</strong> — "remain in me, and I in you." The aorist imperative <em>meínate</em> — "begin and continue to remain" — issues the central command of the vine discourse. <em>Menō</em> (G3306) occurs 11 times in 15:1–16, making it the structural verb of the passage. <strong>καθὼς τὸ κλῆμα οὐ δύναται καρπὸν φέρειν ἀφ᾽ ἑαυτοῦ</strong> — "just as the branch cannot bear fruit of itself." <em>Ou dúnatai</em> — cannot, not merely does not. The incapacity is organic: separated from the vine, the branch has no sap, no life, no possibility of fruit. The analogy holds for the disciples: spiritual fruitfulness is not a human achievement but a product of union.</p>',
    "5": '<p><strong>ἐγώ εἰμι ἡ ἄμπελος, ὑμεῖς τὰ κλήματα</strong> — the I-AM saying is repeated in its shorter form (without <em>alēthinē</em>), now paired with explicit identification of the disciples as branches. The juxtaposition is stark: "I am the vine; you are the branches." The grammar keeps the distinction: Jesus is the vine-stock itself, the source; the disciples are the extensions. <strong>ὁ μένων ἐν ἐμοὶ κἀγὼ ἐν αὐτῷ οὗτος φέρει καρπὸν πολύν</strong> — "the one remaining in me and I in him — this one bears much fruit." The mutual indwelling is inseparable from fruitfulness. <strong>χωρὶς ἐμοῦ οὐ δύνασθε ποιεῖν οὐδέν</strong> — "apart from me you can do nothing." <em>Chōrís</em> (G5565) — apart from, separate from. <em>Ouden</em> — nothing, absolutely nothing. No qualification; the totality of fruitful work depends on union with Christ.</p>',
    "6": '<p><strong>ἐὰν μή τις μένῃ ἐν ἐμοί, ἐβλήθη ἔξω ὡς τὸ κλῆμα</strong> — "if anyone does not remain in me, he is thrown outside like the branch." The aorist passive <em>eblēthē</em> — "was thrown" — is gnomic aorist, expressing a typical or certain result as if it has already occurred. <strong>καὶ ἐξηράνθη</strong> — "and withered." The drying out follows inevitably from separation; it is not imposed but natural. <strong>καὶ συνάγουσιν αὐτὰ καὶ εἰς τὸ πῦρ βάλλουσιν</strong> — "and they gather them and throw them into the fire." The third-person plural "they" is indefinite — "people gather them" — focusing on the process, not an agent. The image of fire echoes the Baptist\'s warning (Matt 3:10; Luke 3:9) about trees without fruit being cut and burned.</p>',
    "7": '<p><strong>ἐὰν μείνητε ἐν ἐμοὶ καὶ τὰ ῥήματά μου ἐν ὑμῖν μείνῃ</strong> — "if you remain in me and my words remain in you." Two conditions, both present subjunctive: the mutual remaining of disciples in Jesus and of Jesus\'s words (<em>rhēmata</em>) in the disciples. <em>Rhēmata</em> (plural of <em>rhēma</em>, G4487) — the specific sayings, the individual words — as opposed to <em>logos</em> (the unified word or message). <strong>ὃ ἐὰν θέλητε αἰτήσασθε</strong> — "ask whatever you wish." The aorist imperative <em>aitēsasthe</em> — the command to petition. The condition on asking is not arbitrary desire but the double remaining: one who remains in Jesus and has Jesus\'s words remaining in them will, by that very formation, want what the Father wills.</p>',
    "8": '<p><strong>ἐν τούτῳ ἐδοξάσθη ὁ πατήρ μου, ἵνα καρπὸν πολὺν φέρητε</strong> — "in this is my Father glorified — that you bear much fruit." The aorist passive <em>edoxasthē</em> — "was glorified" — is again gnomic: the bearing of fruit constitutes the Father\'s glorification as a realized reality. <strong>καὶ γένησθε ἐμοὶ μαθηταί</strong> — "and you become my disciples." <em>Génēsthe</em> (G1096, aorist subjunctive of <em>ginomai</em>) — become, come to be. Discipleship is not a static status but an ongoing becoming that fruit-bearing both expresses and constitutes.</p>',
    "9": '<p><strong>καθὼς ἠγάπησέν με ὁ πατήρ, κἀγὼ ὑμᾶς ἠγάπησα</strong> — "as the Father loved me, I also loved you." Both verbs are aorist — completed historical acts of love. The Father\'s love for the Son and the Son\'s love for the disciples are structurally parallel: the same kind of love, the same verb, the same tense. This is not analogy but derivation — Jesus\'s love for the disciples flows from and replicates the Father\'s love for him. <strong>μείνατε ἐν τῇ ἀγάπῃ τῇ ἐμῇ</strong> — "remain in my love." The aorist imperative <em>meínate</em> here modifies the key Johannine command: abiding in Jesus (vv4–7) is now specified as abiding in his love. Love is not an addition to union with Christ — it is what union with Christ feels like from the inside.</p>',
    "10": '<p><strong>ἐὰν τὰς ἐντολάς μου τηρήσητε, μενεῖτε ἐν τῇ ἀγάπῃ μου</strong> — "if you keep my commandments, you will remain in my love." The future indicative <em>meneite</em> — this is not a conditional threat but a description of how remaining-in-love works: obedience is the relational channel. <strong>καθὼς ἐγὼ τὰς ἐντολὰς τοῦ πατρός μου τετήρηκα καὶ μένω ἐν τῇ ἀγάπῃ αὐτοῦ</strong> — "as I have kept my Father\'s commandments and remain in his love." Two tenses: perfect <em>tetērēka</em> ("I have kept and it stands kept") + present <em>menō</em> ("I remain"). Jesus\'s own Sonship is the template for the disciples\' discipleship: his keeping of the Father\'s commands is both the model and the ground of theirs.</p>',
    "11": '<p><strong>ταῦτα λελάληκα ὑμῖν ἵνα ἡ χαρὰ ἡ ἐμὴ ἐν ὑμῖν ᾖ</strong> — "these things I have spoken to you so that my joy may be in you." The perfect <em>lelalēka</em> again — completed disclosure. The purpose clause specifies the goal: not obedience for its own sake but the transmission of Christ\'s own joy. <em>Chará</em> (G5479, joy) — the noun from <em>chaírō</em> (to rejoice). <strong>καὶ ἡ χαρὰ ὑμῶν πληρωθῇ</strong> — "and your joy may be fulfilled/completed." <em>Plēroō</em> (G4137, aorist passive subjunctive) — to fill to fullness. The same verb used for Scripture\'s fulfillment; joy is "fulfilled" as a promise or vessel is filled to completion. Joy is the goal and product of abiding, not a byproduct.</p>',
    "12": '<p><strong>αὕτη ἐστὶν ἡ ἐντολὴ ἡ ἐμή, ἵνα ἀγαπᾶτε ἀλλήλους</strong> — "this is my commandment: that you love one another." The singular <em>entolē</em> — "commandment" — here, after the plural "commandments" in vv10, 21, 14:15. The plural commands are gathered into one: mutual love. <strong>καθὼς ἠγάπησα ὑμᾶς</strong> — "as I loved you." The aorist again — Jesus\'s completed act of love is the standard and measure. "Love one another" without this qualifier would be ambiguous; "as I loved you" sets the definition by what will happen at the cross.</p>',
    "13": '<p><strong>μείζονα ταύτης ἀγάπην οὐδεὶς ἔχει</strong> — "greater than this love no one has." The superlative of agapē is defined by its limit: giving life. <em>Meizōna</em> (G3187) — greater, highest — comparative used for the superlative. <strong>ἵνα τις τὴν ψυχὴν αὐτοῦ θῇ ὑπὲρ τῶν φίλων αὐτοῦ</strong> — "that one lays down his life for his friends." <em>Psuchēn</em> (G5590) — soul, life, the whole self. <em>Títhēmi</em> (G5087) — to lay down, to put — the verb Jesus consistently uses for his own death (10:11, 15, 17, 18). The present subjunctive <em>thē</em> presents the action as a particular case. The "friends" (<em>philoi</em>) here are the disciples — not the universal humanitarian but the covenanted community. This verse defines the standard that v12 ("love as I loved you") enacts.</p>',
    "14": '<p><strong>ὑμεῖς φίλοι μού ἐστε ἐὰν ποιῆτε ἃ ἐγὼ ἐντέλλομαι ὑμῖν</strong> — "you are my friends if you do what I command you." The conditional is present subjunctive — ongoing doing. <em>Phílos</em> (G5384) — friend, one who is dear, a beloved companion. In the patronage world, <em>philos</em> carried significant social weight: a friend of the patron was one who had privileged access and trust. The condition — doing what Jesus commands — is not a transactional requirement but an organic description: friendship with Jesus is constituted by alignment with his will, as obedience to the Father constitutes the Son\'s relationship with him.</p>',
    "15": '<p><strong>οὐκέτι λέγω ὑμᾶς δούλους</strong> — "no longer do I call you servants/slaves." <em>Doúlos</em> (G1401) — slave, bond-servant. In the honor-shame world, the slave does not know the master\'s plans — only instructions. <strong>ὑμᾶς δὲ εἴρηκα φίλους</strong> — "but I have called you friends." Perfect <em>eirēka</em> — a declaration that stands. <strong>ὅτι πάντα ἃ ἤκουσα παρὰ τοῦ πατρός μου ἐγνώρισα ὑμῖν</strong> — "because all that I heard from my Father I have made known to you." Two aorists: <em>ēkousa</em> (I heard) and <em>egnōrisa</em> (I made known). The disclosure is complete and total — <em>panta</em> (all things). The disciples are <em>philoi</em> because they have been admitted into the counsel of God that Jesus received from the Father.</p>',
    "16": '<p><strong>οὐχ ὑμεῖς με ἐξελέξασθε, ἀλλ᾽ ἐγὼ ἐξελεξάμην ὑμᾶς</strong> — "not you chose me, but I chose you." Both verbs are aorist: the election is a completed historical act. <em>Eklégomai</em> (G1586) — to choose, to select out from a larger group. The emphatic pronoun contrast — <em>ouch hymeis</em> vs. <em>all᾽ egō</em> — makes the priority of the divine initiative absolute. <strong>καὶ ἔθηκα ὑμᾶς ἵνα ὑμεῖς ὑπάγητε καὶ καρπὸν φέρητε</strong> — "and I appointed you so that you might go and bear fruit." <em>Títhēmi</em> (G5087) — to place, to appoint — used for laying down the life (10:11), now for commissioning. The election is purposive: chosen for mission, not merely for status. <strong>καρπὸς ὑμῶν μένῃ</strong> — "your fruit might remain." <em>Menō</em> again: the fruit produced by those remaining in the vine is itself characterized by remaining — enduring, permanent results.</p>',
    "17": '<p><strong>ταῦτα ἐντέλλομαι ὑμῖν, ἵνα ἀγαπᾶτε ἀλλήλους</strong> — the command of v12 is repeated exactly: the vine discourse returns to its ethical center. The repetition brackets the intermediate material (vv13–16) as the ground and explication of mutual love. The Evangelist frames the commandment twice: it is the command, and it requires a reason, and the reason is given between the two statements of the command.</p>',
    "18": '<p><strong>εἰ ὁ κόσμος ὑμᾶς μισεῖ, γινώσκετε ὅτι ἐμὲ πρῶτον ὑμῶν μεμίσηκεν</strong> — "if the world hates you, know that it has hated me before you." The perfect <em>memísēken</em> — "has hated and continues to hate." Jesus\'s being-hated is a completed, standing fact that precedes and explains the disciples\' experience. <em>Ginōskete</em> can be indicative ("you know") or imperative ("know!") — either reading makes sense: the disciples either already know this or need to know it as a ground for resilience.</p>',
    "19": '<p><strong>εἰ ἐκ τοῦ κόσμου ἦτε, ὁ κόσμος ἂν τὸ ἴδιον ἐφίλει</strong> — "if you were of the world, the world would love its own." The conditional is past contrary-to-fact: <em>ēte</em> (imperfect, you were) + <em>an ephílei</em> (would love). <em>To ídion</em> — "its own" — the world loves what belongs to it, what shares its nature. <strong>ὅτι δὲ ἐκ τοῦ κόσμου οὐκ ἐστέ, ἀλλ᾽ ἐγὼ ἐξελεξάμην ὑμᾶς ἐκ τοῦ κόσμου</strong> — "but because you are not of the world, but I chose you out of the world." The election in v16 now has a negative implication: to be chosen out of the world is to be set against it. <em>Ek tou kosmou</em> — "out of the world" — spatial metaphor of extraction from a domain.</p>',
    "20": '<p><strong>μνημονεύετε τοῦ λόγου οὗ ἐγὼ εἶπον ὑμῖν</strong> — "remember the word that I said to you." <em>Mnēmoneuete</em> (G3421, present imperative) — keep on remembering. The word is the servant-master proverb: "a servant is not greater than his master." This appeared in the footwashing scene (13:16); here it is applied to persecution: the treatment of the master predicts and defines the treatment of the servants. <strong>εἰ ἐμὲ ἐδίωξαν, καὶ ὑμᾶς διώξουσιν</strong> — "if they persecuted me, they will also persecute you." The aorist <em>ediōxan</em> and the future <em>diōxousin</em> frame the disciples\' future in the pattern of Jesus\'s past.</p>',
    "21": '<p><strong>ἀλλὰ ταῦτα πάντα ποιήσουσιν ὑμῖν διὰ τὸ ὄνομά μου</strong> — "but all these things they will do to you on account of my name." The phrase <em>dia to onoma mou</em> — "on account of my name" — makes the persecution christological: the disciples are targeted not for their own sake but because of their association with Jesus. <strong>ὅτι οὐκ οἴδασιν τὸν πέμψαντά με</strong> — "because they do not know the one who sent me." The perfect <em>oidasin</em> — "they have not come to know and it stands unknown." The world\'s hatred of Jesus and his followers stems from its fundamental not-knowing of the Father.</p>',
    "22": '<p><strong>εἰ μὴ ἦλθον καὶ ἐλάλησα αὐτοῖς, ἁμαρτίαν οὐκ εἴχοσαν</strong> — "if I had not come and spoken to them, they would not have sin." The condition is past contrary-to-fact: <em>ēlthon</em> and <em>elalēsa</em> (aorists of real events) are cast counterfactually. The point is not that Jesus\'s coming creates sin but that it removes the excuse for not-knowing. <strong>νῦν δὲ πρόφασιν οὐκ ἔχουσιν περὶ τῆς ἁμαρτίας αὐτῶν</strong> — "but now they have no excuse for their sin." <em>Próphasis</em> (G4392) — a pretext, a plausible reason for denial. The coming of the light makes darkness inexcusable.</p>',
    "23": '<p><strong>ὁ ἐμὲ μισῶν καὶ τὸν πατέρα μου μισεῖ</strong> — "the one hating me also hates my Father." The logic of Johannine identity: to hate the Son is to hate the one who sent him, because to see the Son is to see the Father (14:9). There is no access to the Father that bypasses the Son. The two loves and two hates are structurally identical.</p>',
    "24": '<p><strong>εἰ τὰ ἔργα μὴ ἐποίησα ἐν αὐτοῖς ἃ οὐδεὶς ἄλλος ἐποίησεν</strong> — "if I had not done among them the works that no one else did." <em>Oudeis allos</em> — no one else. The works of Jesus are categorically unique — not merely impressive but without precedent. <strong>ἁμαρτίαν οὐκ εἴχοσαν</strong> — "they would not have sin" — the same construction as v22: the works, like the words, remove the excuse of ignorance. Rejection after seeing the unique works is culpable rejection.</p>',
    "25": '<p><strong>ἀλλ᾽ ἵνα πληρωθῇ ὁ λόγος ὁ ἐν τῷ νόμῳ αὐτῶν γεγραμμένος</strong> — "but that the word written in their law might be fulfilled." <em>Plēroō</em> (G4137, aorist passive subjunctive) — the fulfillment formula. The phrase "their law" is not dismissive but rhetorically pointed: Jesus cites their own scriptures against them. <strong>ὅτι ἐμίσησάν με δωρεάν</strong> — "that they hated me without cause." <em>Dōreán</em> (G1432) — gratis, freely, without payment or reason. The citation draws from Ps 35:19 or 69:4. The hatred is gratuitous: there is no provocation in Jesus that grounds it; the antipathy is self-originating in the world\'s alienation from God.</p>',
    "26": '<p><strong>ὅταν ἔλθῃ ὁ παράκλητος ὃν ἐγὼ πέμψω ὑμῖν παρὰ τοῦ πατρός</strong> — the third Paraclete saying, and here the sending agent shifts again to Jesus: "whom I will send to you from the Father." In 14:16, the Father sends in response to the Son\'s prayer; in 14:26, the Father sends in the Son\'s name; here, the Son sends from the Father. The two missions (Father-sends, Son-sends) are held in tension without contradiction, reflecting the coinherence of the persons. <strong>τὸ πνεῦμα τῆς ἀληθείας ὃ παρὰ τοῦ πατρὸς ἐκπορεύεται</strong> — "the Spirit of truth who proceeds from the Father." <em>Ekporeúomai</em> (G1607) — to go out from, to proceed out of. This verb became the focus of the <em>Filioque</em> controversy (whether the Spirit proceeds from the Father alone or from the Father and the Son). The verse says "from the Father" without "and the Son" — the sending (economic mission) and the eternal procession (ontological origin) are distinct questions. <strong>ἐκεῖνος μαρτυρήσει περὶ ἐμοῦ</strong> — "that one will testify concerning me." The Spirit\'s primary role here is witness to Jesus, not independent revelation.</p>',
    "27": '<p><strong>καὶ ὑμεῖς δὲ μαρτυρεῖτε</strong> — "and you also testify." Present imperative — ongoing witness. The disciples bear witness alongside the Spirit: two witnesses, consistent with the requirement of Deut 17:6 and 19:15. The ground for their witness: <strong>ὅτι ἀπ᾽ ἀρχῆς μετ᾽ ἐμοῦ ἐστε</strong> — "because you have been with me from the beginning." Perfect participle implied: their continuous presence from the beginning qualifies them as eyewitnesses. "The beginning" echoes 1:1 and 1 John 1:1 — the Johannine community\'s foundational claim to original witness.</p>'
  },
  "16": {
    "1": '<p><strong>ταῦτα λελάληκα ὑμῖν ἵνα μὴ σκανδαλισθῆτε</strong> — "these things I have spoken to you so that you may not stumble." The perfect <em>lelalēka</em> — completed, standing disclosure. <em>Skandalísthēte</em> (G4624, aorist passive subjunctive of <em>skandalízō</em>) — to stumble, to fall into a trap, to be made to fall. The word <em>skandalon</em> (G4625) is a snare or stumbling-block; here the stumbling is apostasy under pressure. The Farewell Discourse as a whole — the promise of the Paraclete, the vine and branches, the friendship promise — is given with this explicit protective purpose.</p>',
    "2": '<p><strong>ἀποσυναγώγους ποιήσουσιν ὑμᾶς</strong> — "they will make you expelled from the synagogue." <em>Aposynágōgos</em> (G656) — a rare compound occurring only three times in the NT, all in John (9:22; 12:42; 16:2). This was formal exclusion from Jewish communal life — loss of legal standing, social network, family ties, and economic participation. The term reflects the painful reality of Jewish believers being expelled from synagogues in the late first century. <strong>ἀλλ᾽ ἔρχεται ὥρα ἵνα πᾶς ὁ ἀποκτείνας ὑμᾶς δόξῃ λατρείαν προσφέρειν τῷ θεῷ</strong> — "but an hour is coming when everyone who kills you will think he is offering service to God." <em>Latreían prospherein</em> — "offering service/worship" — a cultic term used for religious devotion. The persecution of Jesus\'s followers is framed as religiously motivated violence; the persecutors believe they are acting for God.</p>',
    "3": '<p><strong>καὶ ταῦτα ποιήσουσιν ὅτι οὐκ ἔγνωσαν τὸν πατέρα οὐδὲ ἐμέ</strong> — "and they will do these things because they have not known the Father or me." The aorist <em>egnōsan</em> — "they did not come to know." The not-knowing is the theological root of the violence. The diagnostic function of Christ\'s coming (15:22–24) is here applied to the persecutors: they do not know the God in whose name they act.</p>',
    "4": '<p><strong>ἀλλὰ ταῦτα λελάληκα ὑμῖν ἵνα ὅταν ἔλθῃ ἡ ὥρα αὐτῶν μνημονεύητε αὐτῶν</strong> — "but these things I have spoken to you so that when their hour comes, you may remember them." The prophetic-predictive function of the Farewell Discourse is made explicit: the disciples will recall these warnings when the persecutions begin. <em>Mnēmoneuēte</em> (G3421, present subjunctive) — keep remembering. <strong>ὅτι ἐγὼ εἶπον ὑμῖν</strong> — "that I told you." The recollection is of Jesus\'s own speech — the Evangelist presents the disciples as post-resurrection readers connecting their experience to these words.</p>',
    "5": '<p><strong>νῦν δὲ ὑπάγω πρὸς τὸν πέμψαντά με</strong> — "but now I am going to the one who sent me." <em>Hypágō</em> (G5217, present indicative) — Jesus is going, already in motion. <strong>καὶ οὐδεὶς ἐξ ὑμῶν ἐρωτᾷ με ποῦ ὑπάγεις</strong> — "and none of you asks me, \'Where are you going?\'" This seems to contradict 13:36 (Peter\'s question) and 14:5 (Thomas\'s question), both of which are questions about the destination. The Evangelist may mean that no one is now pressing the question with genuine concern for Jesus\'s destination — grief has displaced inquiry. The disciples have turned inward to their own sorrow rather than outward to Jesus\'s mission.</p>',
    "6": '<p><strong>ἀλλ᾽ ὅτι ταῦτα λελάληκα ὑμῖν, ἡ λύπη πεπλήρωκεν ὑμῶν τὴν καρδίαν</strong> — "but because I have spoken these things to you, grief has filled your heart." Two perfects: <em>lelalēka</em> (I have spoken, it stands spoken) and <em>peplērōken</em> (grief has filled, and it stands filled). The filling of the heart with grief mirrors the promise that joy will be "completed" (<em>plēroō</em>, v24) — the same verb for both states. The disciples are at the stage of grief-saturation before the Spirit\'s arrival reverses it.</p>',
    "7": '<p><strong>ἀλλ᾽ ἐγὼ τὴν ἀλήθειαν λέγω ὑμῖν</strong> — "but I tell you the truth." The <em>alētheia</em> formula grounds what follows as genuine disclosure, not comfort fabricated to ease their distress. <strong>συμφέρει ὑμῖν ἵνα ἐγὼ ἀπέλθω</strong> — "it is to your advantage that I go away." <em>Symphérei</em> (G4851, impersonal present of <em>symphérō</em>) — it is profitable, expedient, beneficial. The word is commercial in register: the departure of Jesus produces a net gain. The basis: <strong>ἐὰν γὰρ μὴ ἀπέλθω, ὁ παράκλητος οὐ μὴ ἔλθῃ πρὸς ὑμᾶς</strong> — "for if I do not go away, the Advocate will not come to you." The double negative <em>ou mē</em> with the subjunctive is the strongest Greek denial: absolutely will not come. The physical presence of the incarnate Jesus and the universal presence of the Spirit are mutually exclusive states; the departure is the condition of the gift.</p>',
    "8": '<p><strong>ἐλέγξει τὸν κόσμον περὶ ἁμαρτίας καὶ περὶ δικαιοσύνης καὶ περὶ κρίσεως</strong> — "he will convict the world concerning sin and concerning righteousness and concerning judgment." <em>Eléngchō</em> (G1651) — a forensic verb spanning "to expose," "to convict," "to prove guilty," "to convince." In legal usage it means to bring evidence that establishes guilt; the outcome may be conviction leading to repentance or shame. The Spirit performs this in the world as a whole — the <em>kosmos</em> stands in a courtroom, and the Spirit is the prosecuting attorney who brings light on three counts: sin, righteousness, judgment. Each is unpacked in vv9–11.</p>',
    "9": '<p><strong>περὶ ἁμαρτίας μέν, ὅτι οὐ πιστεύουσιν εἰς ἐμέ</strong> — "concerning sin, because they do not believe in me." The world is convicted of sin not for a catalogue of moral failures but for the foundational sin: unbelief in Jesus. <em>Hamartía</em> (G266) — sin as a condition, not merely individual acts; the world\'s fundamental orientation away from God. The present tense <em>pisteuousin</em> — "they are not believing" — marks it as an ongoing state. The singular sin that the Spirit convicts is the rejection of the one who revealed the Father.</p>',
    "10": '<p><strong>περὶ δικαιοσύνης δέ, ὅτι πρὸς τὸν πατέρα ὑπάγω</strong> — "concerning righteousness, because I am going to the Father." <em>Dikaiosýnē</em> (G1343, dispute_level 4) — righteousness, justification, rectitude. The Spirit\'s convicting work here is vindicating: Jesus\'s departure to the Father is itself the demonstration of righteousness. The world condemned Jesus as a blasphemer and executed him; the ascension reveals that he was righteous, vindicated by the Father who received him. The Spirit reproves the world\'s verdict. <strong>καὶ οὐκέτι θεωρεῖτέ με</strong> — "and you see me no longer" — the disciples\' loss of direct sight of Jesus is connected to the world\'s being reproved: the Spirit continues the work of making Jesus\'s righteousness present even in his absence.</p>',
    "11": '<p><strong>περὶ δὲ κρίσεως, ὅτι ὁ ἄρχων τοῦ κόσμου τούτου κέκριται</strong> — "concerning judgment, because the ruler of this world has been judged." <em>Kékritai</em> — perfect passive: "has been judged and it stands judged." The ruler\'s judgment is already accomplished; the cross is the decisive verdict. <em>Árchōn</em> (G758, ruler) — the same title as in 12:31 ("now the ruler of this world will be cast out") and 14:30. The Spirit convicts the world of judgment not by announcing a future event but by exposing that judgment has already occurred: the prince\'s authority has been broken at the cross.</p>',
    "12": '<p><strong>ἔτι πολλὰ ἔχω ὑμῖν λέγειν, ἀλλ᾽ οὐ δύνασθε βαστάζειν ἄρτι</strong> — "I have many more things to say to you, but you cannot bear them now." <em>Bastázō</em> (G941) — to carry, to bear a weight. The disciples\' incapacity is temporary and situational — "now" (<em>arti</em>) — not permanent. The incompleteness of Jesus\'s teaching is presented not as a defect but as a pedagogical limit awaiting the Spirit\'s coming. This verse is the hinge between the Paraclete\'s three-pronged work in the world (vv8–11) and his revelatory work in the community (vv13–15).</p>',
    "13": '<p><strong>ὅταν δὲ ἔλθῃ ἐκεῖνος, τὸ πνεῦμα τῆς ἀληθείας, ὁδηγήσει ὑμᾶς εἰς τὴν ἀλήθειαν πᾶσαν</strong> — "when that one comes, the Spirit of truth, he will guide you into all truth." <em>Hodēgéō</em> (G3594) — to guide, to lead the way, as a guide leads travelers on a road. The Spirit is not a lecturer but a guide who accompanies the journey into truth. <em>Eis tēn alētheian pāsan</em> — "into all the truth" — the scope is comprehensive; what Jesus could not yet say (v12) the Spirit will lead them into. This verse grounds the apostolic teaching of the NT as Spirit-guided revelation.</p><p><strong>οὐ γὰρ λαλήσει ἀφ᾽ ἑαυτοῦ</strong> — "for he will not speak from himself." The Spirit\'s dependence on the Son mirrors the Son\'s dependence on the Father (14:10). The pattern of the missions is consistent: the Father speaks through the Son; the Son speaks through the Spirit. <strong>ἀλλ᾽ ὅσα ἀκούσει λαλήσει</strong> — "but what he hears he will speak." The Spirit\'s speaking is reception before it is transmission — he hears from the Son and speaks to the community.</p>',
    "14": '<p><strong>ἐκεῖνος ἐμὲ δοξάσει, ὅτι ἐκ τοῦ ἐμοῦ λήμψεται</strong> — "that one will glorify me, because from what is mine he will receive." The Spirit\'s ultimate purpose is to glorify Jesus — not to be an independent revelatory center but to make Jesus\'s person and work known. <em>Ek tou emou</em> — "from what is mine" — the Spirit receives from the treasury of the Son. <em>Lēmpsetai</em> (G2983, future of <em>lambánō</em>) — will receive. <strong>καὶ ἀναγγελεῖ ὑμῖν</strong> — "and will announce/declare to you." <em>Anangéllō</em> (G312) — to report, to declare in detail. The Spirit\'s announcing of what is Christ\'s constitutes his ministry of glorification.</p>',
    "15": '<p><strong>πάντα ὅσα ἔχει ὁ πατὴρ ἐμά ἐστιν</strong> — "all that the Father has is mine." The claim is total: no division of possession between Father and Son. This is the ground for the Spirit\'s receiving "from what is mine" (v14): the Son\'s possessions include everything the Father has. <strong>διὰ τοῦτο εἶπον ὅτι ἐκ τοῦ ἐμοῦ λαμβάνει</strong> — "for this reason I said that he receives from what is mine." The repetition of v14\'s formula grounds the Spirit\'s revelatory role in the ontological communion of Father and Son: what belongs to the Father belongs to the Son; the Spirit draws from that shared plenitude.</p>',
    "16": '<p><strong>μικρὸν καὶ οὐκέτι θεωρεῖτέ με, καὶ πάλιν μικρὸν καὶ ὄψεσθέ με</strong> — "a little while and you will no longer see me, and again a little while and you will see me." Two <em>mikrón</em> (G3397, little while) constructions bracket the period of Jesus\'s absence. Two seeing-verbs: <em>theōréō</em> (G2334, perceptual, sustained seeing — the disciples\' present sight) and <em>horáō</em> (G3708, to see, often of revelatory seeing). After the first little while, the perceptual seeing ends; after the second, the seeing of horáō begins — perhaps the resurrection appearances, or the eschatological vision, or the Spirit-mediated knowing of 14:19–20. The Evangelist leaves the referent deliberately multi-dimensional.</p>',
    "17": '<p>Some of the disciples said to one another — the Evangelist does not name them — "What is this that he says to us, <em>a little while and you will not see me, and again a little while and you will see me</em>?" The repetition of Jesus\'s exact words signals confusion, not hostile rejection. The disciples are bewildered, not resistant. The Evangelist\'s technique here is consistent with the pattern of misunderstanding that runs through the Gospel (3:4; 4:11; 6:42; 11:12) — misunderstanding that creates the occasion for fuller disclosure.</p>',
    "18": '<p><strong>τί ἐστιν τοῦτο ὃ λέγει, τὸ μικρόν</strong> — "what is this <em>little while</em> he speaks of?" The disciples focus on the phrase <em>to mikrón</em> — the "little while" has become a puzzle. <strong>οὐκ οἴδαμεν τί λαλεῖ</strong> — "we do not know what he is saying." The combination <em>ouk oidamen</em> — "we have not come to know" (perfect) — and the present <em>laleí</em> — "is saying" — expresses honest incomprehension of an ongoing utterance.</p>',
    "19": '<p>Jesus perceives their desire to ask — <em>egnō</em> (aorist of <em>ginōskō</em>, G1097, the Evangelist\'s verb for Jesus\'s supernatural perception of human thought) — and addresses the confusion directly. The rhetorical question <strong>περὶ τούτου ζητεῖτε μετ᾽ ἀλλήλων</strong> — "are you asking one another about this?" — is not accusatory but invitational: bring the question to me. The disciples\' intramural discussion is redirected to direct inquiry of Jesus.</p>',
    "20": '<p><strong>ἀμὴν ἀμὴν λέγω ὑμῖν ὅτι κλαύσετε καὶ θρηνήσετε ὑμεῖς</strong> — the solemn double-<em>amēn</em> introduces the birth-pain analogy. <em>Klaíō</em> (G2799) — to weep, the verb used for Mary\'s weeping at the tomb (20:11) and for the raising of Lazarus (11:31). <em>Thrēnéō</em> (G2354) — to mourn loudly, to lament. Both futures describe what the disciples will do. <strong>ὁ δὲ κόσμος χαρήσεται</strong> — "but the world will rejoice." The world\'s rejoicing at the crucifixion is a horrifying reversal of the expected order. <strong>ἡ λύπη ὑμῶν εἰς χαρὰν γενήσεται</strong> — "your grief will become joy." <em>Genēsetai</em> (future of <em>ginomai</em>) — will become, will turn into. The grief does not merely produce joy as a secondary effect; it is itself transformed.</p>',
    "21": '<p><strong>ἡ γυνὴ ὅταν τίκτῃ λύπην ἔχει</strong> — "the woman when she gives birth has grief." <em>Tíktō</em> (G5088) — to give birth, to bring forth. The analogy is precise: the grief of labor is real and intense (<em>hē hōra autēs</em> — "her hour"), but the birth itself annihilates its memory: <strong>οὐκέτι μνημονεύει τῆς θλίψεως διὰ τὴν χαρὰν ὅτι ἐγεννήθη ἄνθρωπος εἰς τὸν κόσμον</strong> — "she remembers no more the anguish because of the joy that a man was born into the world." <em>Thrípsis</em> (G2347) — pressure, anguish, tribulation. <em>Egerennēthē</em> (aorist passive) — was born: the new life is not the mother\'s achievement but a happening that comes upon the world.</p>',
    "22": '<p><strong>καὶ ὑμεῖς οὖν νῦν μὲν λύπην ἔχετε</strong> — "and you therefore now indeed have grief." The grief is present-tense and real. <strong>πάλιν δὲ ὄψομαι ὑμᾶς</strong> — "but I will see you again." The future <em>opsomai</em> (G3708) — the same word used in v16 for the disciples\' seeing; here Jesus uses it for his own seeing of them. The reunion is mutual seeing. <strong>καὶ χαρήσεται ὑμῶν ἡ καρδία, καὶ τὴν χαρὰν ὑμῶν οὐδεὶς αἴρει ἀφ᾽ ὑμῶν</strong> — "and your heart will rejoice, and no one takes your joy from you." <em>Aírō</em> (G142) — to take away — the same verb as in 15:2 (removing branches). The permanence of the resurrection joy is absolute: it is beyond the reach of any human or cosmic removal.</p>',
    "23": '<p><strong>καὶ ἐν ἐκείνῃ τῇ ἡμέρᾳ ἐμὲ οὐκ ἐρωτήσετε οὐδέν</strong> — "and in that day you will ask me nothing." The question-verb here is <em>erōtáō</em> (G2065) — to inquire, to ask directly in conversation, as one asks a teacher. <strong>ἀμὴν ἀμὴν λέγω ὑμῖν, ὅ τι ἂν αἰτήσητε τὸν πατέρα ἐν τῷ ὀνόματί μου δώσει ὑμῖν</strong> — the prayer-verb shifts to <em>aitéō</em> (G154) — the asking of petition, of request. The distinction: after the resurrection, the disciples will not need to ask Jesus conversational questions (because they will understand); their asking will be petitionary prayer to the Father in Jesus\'s name, which will be answered.</p>',
    "24": '<p><strong>ἕως ἄρτι οὐκ ᾐτήσατε οὐδὲν ἐν τῷ ὀνόματί μου</strong> — "until now you have asked nothing in my name." The aorist <em>ētēsate</em> — a summary of the entire period of the disciples\' pre-resurrection existence. Prayer "in the name of Jesus" is post-resurrection practice; it requires the revelation of who Jesus is that only the resurrection fully provides. <strong>αἰτεῖτε καὶ λήμψεσθε</strong> — "ask and you will receive." Present imperative + future indicative: the command to ask and the certainty of reception. <strong>ἵνα ἡ χαρὰ ὑμῶν ᾖ πεπληρωμένη</strong> — "so that your joy may be fulfilled." <em>Peplērōmenē</em> (G4137, perfect passive participle) — a completed fullness of joy as the goal of answered prayer.</p>',
    "25": '<p><strong>ταῦτα ἐν παροιμίαις λελάληκα ὑμῖν</strong> — "these things in figures of speech I have spoken to you." <em>Paroiimía</em> (G3942) — a proverb, a dark saying, an indirect or figurative speech form. The entire vine discourse (ch. 15) and the "little while" language are examples of <em>paroimía</em>. <strong>ἔρχεται ὥρα ὅτε οὐκέτι ἐν παροιμίαις λαλήσω ὑμῖν</strong> — "an hour is coming when I will no longer speak to you in figures." The promised plainness (<em>parrhēsía</em>) replaces the figurative mode — a promise fulfilled in the post-resurrection conversations (20:19–23; Acts 1:3) and in the Spirit\'s guiding into all truth (v13).</p>',
    "26": '<p><strong>ἐν ἐκείνῃ τῇ ἡμέρᾳ ἐν τῷ ὀνόματί μου αἰτήσεσθε</strong> — "in that day you will ask in my name." The future <em>aitēsesthe</em> — the prayer practice of the resurrection community. <strong>καὶ οὐ λέγω ὑμῖν ὅτι ἐγὼ ἐρωτήσω τὸν πατέρα περὶ ὑμῶν</strong> — "and I do not say that I will ask the Father on your behalf." The present tense <em>legō</em> — Jesus is explicitly clarifying what is not meant. This correction pre-empts the inference that the disciples need an additional intercessor to overcome a reluctant Father; v27 supplies the reason: the Father himself already loves them directly.</p>',
    "27": '<p><strong>αὐτὸς γὰρ ὁ πατὴρ φιλεῖ ὑμᾶς</strong> — "for the Father himself loves you." <em>Autós</em> — emphatic "himself" — the Father personally and directly loves the disciples. The verb here is <em>philéō</em> (G5368) — the love of personal affection, friendship — as opposed to <em>agapáō</em>. The Father\'s love is not mediated through an additional intercessor; he is already disposed toward the disciples in direct personal love. <strong>ὅτι ὑμεῖς ἐμὲ φεφιλήκατε καὶ πεπιστεύκατε ὅτι ἐγὼ παρὰ τοῦ θεοῦ ἐξῆλθον</strong> — "because you have loved me and have believed that I came from God." Both verbs are perfect: <em>pephilēkate</em> (you have loved and it stands) and <em>pepisteukate</em> (you have believed and it stands). The disciples\' faith and love are completed realities that ground the Father\'s direct love for them.</p>',
    "28": '<p><strong>ἐξῆλθον παρὰ τοῦ πατρὸς καὶ ἐλήλυθα εἰς τὸν κόσμον</strong> — "I came out from the Father and have come into the world." Two verbs: <em>exēlthon</em> (aorist — the departure from the Father) and <em>elēlytha</em> (perfect — I have come and am here). The perfect carries the incarnation as a completed act whose result is still present: the Son is here, in the world, having come from the Father. <strong>πάλιν ἀφίημι τὸν κόσμον καὶ πορεύομαι πρὸς τὸν πατέρα</strong> — "again I leave the world and go to the Father." <em>Aphíēmi</em> (G863) — to release, to let go, to leave behind. The entire movement of the incarnation is summarized: out from the Father → into the world → leaving the world → to the Father. The same arc appears in 13:3 and 17:5.</p>',
    "29": '<p>The disciples\' response — <strong>ἴδε νῦν ἐν παρρησίᾳ λαλεῖς</strong> — "see, now you are speaking plainly" — uses <em>parrhēsía</em> (G3954), the promised mode of speaking from v25. The disciples believe the plain speech has arrived. <em>Parrhēsía</em> — speaking openly, without concealment or circumlocution — is the opposite of <em>paroimía</em>. Their confidence is premature; v31 will test its depth.</p>',
    "30": '<p><strong>νῦν οἴδαμεν ὅτι οἶδας πάντα</strong> — "now we know that you know all things." The disciples are stating what has been implicit throughout the Gospel: Jesus\'s supernatural knowledge of human hearts (1:47–48; 4:17–18; 6:64; 11:14). <strong>καὶ οὐ χρείαν ἔχεις ἵνα τίς σε ἐρωτᾷ</strong> — "and you have no need that anyone question you." They recognize that Jesus answered their unvoiced question (v19) — he knew what they wanted to ask before they asked. <strong>ἐν τούτῳ πιστεύομεν ὅτι ἀπὸ θεοῦ ἐξῆλθες</strong> — "by this we believe that you came from God." The aorist <em>exēlthes</em> echoes v28\'s <em>exēlthon</em>: the disciples name what Jesus just stated about himself, now confessing it as their own belief.</p>',
    "31": '<p><strong>ἄρτι πιστεύετε</strong> — "do you now believe?" The word <em>árti</em> (G737) — now, at this moment — carries a tone of gentle irony in context. Jesus accepts neither confirms nor dismisses their confession, but poses the question that exposes the fragility of their moment-of-clarity faith. The next verse (v32) immediately puts the "now" of their belief against the "coming hour" of their scattering.</p>',
    "32": '<p><strong>ἰδοὺ ἔρχεται ὥρα καὶ ἐλήλυθεν</strong> — "behold, an hour is coming and has come." The combination of future (<em>érchetai</em>) and perfect (<em>elēlythen</em>) in the same clause is striking — the hour is both imminent and already present. <strong>ἵνα σκορπισθῆτε ἕκαστος εἰς τὰ ἴδια</strong> — "that you will be scattered, each to his own." <em>Skorpísthēte</em> (G4650, aorist passive subjunctive) — to scatter, to disperse. The Evangelist uses the language of Zech 13:7 ("strike the shepherd and the sheep will be scattered"), cited explicitly in Mark 14:27. <strong>κἀμὲ μόνον ἀφῆτε</strong> — "and you will leave me alone." <em>Aphēte</em> (aorist subjunctive of <em>aphíēmi</em>) — the same verb as "leave" in 14:27 ("I leave you peace") and 16:28 ("I leave the world"). The disciples will leave Jesus; Jesus leaves them peace. The contrast is deliberate. <strong>καὶ οὐκ εἰμὶ μόνος, ὅτι ὁ πατὴρ μετ᾽ ἐμοῦ ἐστιν</strong> — "and I am not alone, because the Father is with me." The disciples\' abandonment does not produce aloneness; the Father\'s presence is constant.</p>',
    "33": '<p><strong>ταῦτα λελάληκα ὑμῖν ἵνα ἐν ἐμοὶ εἰρήνην ἔχητε</strong> — "these things I have spoken to you so that in me you may have peace." The final summary of the entire Farewell Discourse (chs. 14–16). The perfect <em>lelalēka</em> — completed, standing disclosure. The peace is located <em>en emoi</em> — "in me" — not in changed circumstances, not in the absence of trouble. <strong>ἐν τῷ κόσμῳ θλῖψιν ἔχετε</strong> — "in the world you have tribulation." Present indicative — a fact of existence. <em>Thlípsis</em> (G2347) — pressure, compression, tribulation. <strong>ἀλλὰ θαρσεῖτε, ἐγὼ νενίκηκα τὸν κόσμον</strong> — "but take courage — I have overcome the world." <em>Tharséō</em> (G2293, present imperative) — be of good courage, take heart. <em>Neníkēka</em> — perfect: "I have overcome and the overcoming stands." The perfect is the foundation of the imperative: take courage because the victory is already accomplished, already fixed in the past and present simultaneously. The cosmic confrontation Jesus announced (12:31, 14:30) has its verdict: the ruler of the world is judged, the world is overcome, and the overcoming is complete.</p>'
  }
}


def main():
    existing = load_comm('mkt-original', 'john')
    merge_comm(existing, JOHN)
    save_comm('mkt-original', 'john', existing)
    print('John 14–16 mkt-original written.')

if __name__ == '__main__':
    main()
